18	package register_file_pkg is
19	
20	  constant register_width : positive := 32;
21	  subtype register_t is std_ulogic_vector(register_width - 1 downto 0);
22	  constant register_init : register_t := (others => '0');
23	  type register_vec_t is array (integer range <>) of register_t;
24	
25	  type register_mode_t is (
26	    -- Software can read a value that hardware provides.
27	    r,
28	    -- Software can write a value that is available for usage in hardware.
29	    w,
30	    -- Software can write a value and read it back. The written value is available for usage
31	    -- in hardware.
32	    r_w,
33	    -- Software can write a value that is asserted for one cycle in hardware.
34	    wpulse,
35	    -- Software can read a value that hardware provides.
36	    -- Software can write a value that is asserted for one cycle in hardware.
37	    r_wpulse
38	  );
39	
40	  -- If it is a mode where software can read the register.
41	  function is_read_mode(mode : register_mode_t) return boolean;
42	  -- If it is a mode where software can write the register.
43	  function is_write_mode(mode : register_mode_t) return boolean;
44	  -- If it is a mode where software can write the register and the value shall be asserted for
45	  -- one clock cycle in hardware.
46	  function is_write_pulse_mode(mode : register_mode_t) return boolean;
47	  -- If it is a mode where the value that software can read is provided by the 'regs_up' port
48	  -- from the users' application.
49	  -- As opposed to for example Read-Write, where the read value is a loopback of the written value.
50	  function is_application_gives_value_mode(mode : register_mode_t) return boolean;
51	
52	  type register_definition_t is record
53	    -- The index of this register, within the list of registers.
54	    index : natural;
55	    -- The mode of this register.
56	    mode : register_mode_t;
57	    -- The number of data bits that are utilized in this register.
58	    -- Implementations can ignore other bits.
59	    utilized_width : natural range 0 to register_width;
60	  end record;
61	  type register_definition_vec_t is array (natural range <>) of register_definition_t;
62	
63	  -- Get the highest register index that is used in the list of registers.
64	  function get_highest_index(registers : register_definition_vec_t) return natural;
65	
66	  -- Get the number of bits needed to represent the register indices.
67	  -- Note that this does not include the lowest two aligned bits.
68	  function num_address_bits_needed(registers : register_definition_vec_t) return positive;
69	
70	end;
71	
72	package body register_file_pkg is
73	
74	  function is_read_mode(mode : register_mode_t) return boolean is
75	  begin
76	    return mode = r or mode = r_w or mode = r_wpulse;
77	  end function;
78	
79	  function is_write_mode(mode : register_mode_t) return boolean is
80	  begin
81	    return mode = w or mode = r_w or mode = wpulse or mode = r_wpulse;
82	  end function;
83	
84	  function is_write_pulse_mode(mode : register_mode_t) return boolean is
85	  begin
86	    return mode = wpulse or mode = r_wpulse;
87	  end function;
88	
89	  function is_application_gives_value_mode(mode : register_mode_t) return boolean is
90	  begin
91	    return mode = r or mode = r_wpulse;
92	  end function;
93	
94	  function get_highest_index(registers : register_definition_vec_t) return natural is
95	  begin
96	    assert registers(0).index = 0 severity failure;
97	    assert registers(registers'high).index = registers'length - 1 severity failure;
98	    return registers(registers'high).index;
99	  end function;
100	
101	  function num_address_bits_needed(registers : register_definition_vec_t) return positive is
102	    constant max_index : natural := get_highest_index(registers);
103	  begin
104	    if max_index = 0 then
105	      return 1;
106	    end if;
107	
108	    return integer(ceil(log2(real(max_index + 1))));
109	  end function;
110	
111	end;
