1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- Generic, parameterizable, register file for AXI-Lite register buses.
10	-- Is parameterizable via a generic that sets the list of registers, with their modes and their
11	-- default values.
12	--
13	-- The ``regs`` and ``default_values`` generics are designed to get their values
14	-- from a package generated by the :external:ref:`hdl-registers VHDL generator <generator_vhdl>`.
15	-- The values can be constructed by hand as well, of course.
16	--
17	--
18	-- Error handling
19	-- ______________
20	--
21	-- Will respond with ``SLVERR`` on the ``R`` channel when attempting to read a register that
22	--
23	-- 1. Does not exists (``ARADDR`` out of range), or
24	-- 2. Is not of a register type that can be read by the bus (e.g. write only).
25	--
26	-- Similarly, it will respond with ``SLVERR`` on the ``B`` channel when attempting to write a
27	-- register that
28	--
29	-- 1. Does not exists (``AWADDR`` out of range), or
30	-- 2. Is not of a register type that can be written by the bus (e.g. read only).
31	--
32	-- Both cases are handled cleanly without stalling or hanging the AXI-Lite bus.
33	--
34	--
35	-- Reset
36	-- _____
37	--
38	-- This entity features an active-high synchronous reset.
39	-- The reset signal is not required to be connected, as the code uses initial values for
40	-- all registers.
41	-- It can be safe to leave it unconnected and tied to zero.
42	--
43	-- If the reset is asserted, however, the AXI-Lite handshaking state will be reset as well as
44	-- all register values.
45	-- -------------------------------------------------------------------------------------------------
46	
47	library ieee;
48	use ieee.std_logic_1164.all;
49	use ieee.numeric_std.all;
50	
51	library axi_lite;
52	use axi_lite.axi_lite_pkg.all;
53	
54	use work.register_file_pkg.all;
55	
56	
57	entity axi_lite_register_file is
58	  generic (
59	    registers : register_definition_vec_t;
60	    default_values : register_vec_t(registers'range) := (others => (others => '0'))
61	  );
62	  port (
63	    clk : in std_ulogic;
64	    -- Active-high synchronous reset.
65	    -- The code in this entity uses initial values so an initial reset is NOT necessary.
66	    -- This port can safely be left unconnected and tied to zero.
67	    -- If asserted, it will reset the AXI-Lite handshaking state as well as all register values.
68	    reset : in std_ulogic := '0';
69	    --# {{}}
70	    --# Register control bus
71	    axi_lite_m2s : in axi_lite_m2s_t;
72	    axi_lite_s2m : out axi_lite_s2m_t := axi_lite_s2m_init;
73	    --# {{}}
74	    -- Register values
75	    regs_up : in register_vec_t(registers'range) := default_values;
76	    regs_down : out register_vec_t(registers'range) := default_values;
77	    --# {{}}
78	    -- Each bit is pulsed for one cycle when the corresponding register is read/written.
79	    -- For read, the bit is asserted the exact same cycle as the AXI-Lite R transaction occurs.
80	    -- For write, the bit is asserted the cycle after the AXI-Lite W transaction occurs, so that
81	    -- 'regs_down' is updated with the new value.
82	    reg_was_read : out std_ulogic_vector(registers'range) := (others => '0');
83	    reg_was_written : out std_ulogic_vector(registers'range) := (others => '0')
84	  );
85	end entity;
86	
87	architecture a of axi_lite_register_file is
88	
89	  constant num_address_bits : positive := num_address_bits_needed(registers=>registers);
90	  subtype address_range is natural range num_address_bits + 2 - 1 downto 2;
91	
92	  signal reg_values : register_vec_t(registers'range) := default_values;
93	
94	begin
95	
96	  ------------------------------------------------------------------------------
97	  assign_down : process(all)
98	  begin
99	    -- Assign only the bits that are marked as utilized, so there is no risk of confusion/misuse.
100	    for reg_idx in registers'range loop
101	      if is_write_mode(registers(reg_idx).mode) then
102	        regs_down(reg_idx)(registers(reg_idx).utilized_width - 1 downto 0) <= reg_values(reg_idx)(
103	          registers(reg_idx).utilized_width - 1 downto 0
104	        );
105	      end if;
106	    end loop;
107	  end process;
108	
109	
110	  ------------------------------------------------------------------------------
111	  read_block : block
112	    type read_state_t is (ar, r);
113	    signal read_state : read_state_t := ar;
114	    signal read_index : u_unsigned(num_address_bits - 1 downto 0) := (others => '0');
115	  begin
116	
117	    ------------------------------------------------------------------------------
118	    set_status : process(all)
119	    begin
120	      reg_was_read <= (others => '0');
121	
122	      axi_lite_s2m.read.r.resp <= axi_lite_resp_slverr;
123	
124	      -- Set initial values zero.
125	      -- Below we will only assign the bits that are actually utilized by the register.
126	      -- Hopefully, software should not look at any bits outside of the utilized width,
127	      -- but set zero just in case and to avoid confusion.
128	      -- Does not impact netlist build size.
129	      axi_lite_s2m.read.r.data(reg_values(0)'range) <= (others => '0');
130	
131	      for list_idx in registers'range loop
132	        if is_read_mode(registers(list_idx).mode) then
133	          if read_index = list_idx then
134	            axi_lite_s2m.read.r.resp <= axi_lite_resp_okay;
135	            reg_was_read(list_idx) <= axi_lite_m2s.read.r.ready and axi_lite_s2m.read.r.valid;
136	          end if;
137	
138	          for bit_idx in 0 to registers(list_idx).utilized_width - 1 loop
139	            if is_application_gives_value_mode(registers(list_idx).mode) then
140	              if read_index = list_idx then
141	                axi_lite_s2m.read.r.data(bit_idx) <= regs_up(list_idx)(bit_idx);
142	              end if;
143	            else
144	              if read_index = list_idx then
145	                axi_lite_s2m.read.r.data(bit_idx) <= reg_values(list_idx)(bit_idx);
146	              end if;
147	            end if;
148	          end loop;
149	        end if;
150	      end loop;
151	    end process;
152	
153	
154	    ------------------------------------------------------------------------------
155	    read_process : process
156	    begin
157	      wait until rising_edge(clk);
158	
159	      case read_state is
160	        when ar =>
161	          -- Sample always, will only be used if we change state.
162	          read_index <= axi_lite_m2s.read.ar.addr(address_range);
163	
164	          axi_lite_s2m.read.ar.ready <= '1';
165	
166	          if axi_lite_s2m.read.ar.ready and axi_lite_m2s.read.ar.valid then
167	            axi_lite_s2m.read.ar.ready <= '0';
168	
169	            read_state <= r;
170	          end if;
171	
172	        when r =>
173	          axi_lite_s2m.read.r.valid <= '1';
174	
175	          if axi_lite_m2s.read.r.ready and axi_lite_s2m.read.r.valid then
176	            axi_lite_s2m.read.r.valid <= '0';
177	            axi_lite_s2m.read.ar.ready <= '1';
178	
179	            read_state <= ar;
180	          end if;
181	      end case;
182	
183	      if reset then
184	        read_state <= ar;
185	
186	        axi_lite_s2m.read.ar.ready <= '0';
187	        axi_lite_s2m.read.r.valid <= '0';
188	      end if;
189	    end process;
190	
191	  end block;
192	
193	
194	  ------------------------------------------------------------------------------
195	  write_block : block
196	    type write_state_t is (aw, w, b);
197	    signal write_state : write_state_t := aw;
198	    signal write_index : u_unsigned(num_address_bits - 1 downto 0) := (others => '0');
199	  begin
200	
201	    ------------------------------------------------------------------------------
202	    set_status : process
203	    begin
204	      wait until rising_edge(clk);
205	
206	      reg_was_written <= (others => '0');
207	
208	      axi_lite_s2m.write.b.resp <= axi_lite_resp_slverr;
209	
210	      for list_idx in registers'range loop
211	        if is_write_pulse_mode(registers(list_idx).mode) then
212	          for bit_idx in 0 to registers(list_idx).utilized_width - 1 loop
213	            -- Set initial default value.
214	            -- If a write occurs to this register, the value will be asserted for one cycle below.
215	            reg_values(list_idx)(bit_idx) <= default_values(list_idx)(bit_idx);
216	          end loop;
217	        end if;
218	      end loop;
219	
220	      for list_idx in registers'range loop
221	        if is_write_mode(registers(list_idx).mode) then
222	          if write_index = list_idx then
223	            axi_lite_s2m.write.b.resp <= axi_lite_resp_okay;
224	            reg_was_written(list_idx) <= axi_lite_s2m.write.w.ready and axi_lite_m2s.write.w.valid;
225	          end if;
226	
227	          for bit_idx in 0 to registers(list_idx).utilized_width - 1 loop
228	            if write_index = list_idx then
229	              if axi_lite_s2m.write.w.ready and axi_lite_m2s.write.w.valid then
230	                reg_values(list_idx)(bit_idx) <= axi_lite_m2s.write.w.data(bit_idx);
231	              end if;
232	            end if;
233	          end loop;
234	        end if;
235	      end loop;
236	
237	      if reset then
238	        reg_values <= default_values;
239	      end if;
240	    end process;
241	
242	
243	    ------------------------------------------------------------------------------
244	    -- The handshaking is not really optimal, but if it is "optimized" the LUT usage increases
245	    -- by 100% for some reason.
246	    -- Leave as it is for now, might be worth investigating at some point in the future.
247	    write_process : process
248	    begin
249	      wait until rising_edge(clk);
250	
251	      case write_state is
252	        when aw =>
253	          -- Sample always, will only be used if we change state.
254	          write_index <= axi_lite_m2s.write.aw.addr(address_range);
255	
256	          axi_lite_s2m.write.aw.ready <= '1';
257	
258	          if axi_lite_s2m.write.aw.ready and axi_lite_m2s.write.aw.valid then
259	            axi_lite_s2m.write.aw.ready <= '0';
260	            axi_lite_s2m.write.w.ready <= '1';
261	
262	            write_state <= w;
263	          end if;
264	
265	        when w =>
266	          if axi_lite_s2m.write.w.ready and axi_lite_m2s.write.w.valid then
267	            axi_lite_s2m.write.w.ready <= '0';
268	            axi_lite_s2m.write.b.valid <= '1';
269	
270	            write_state <= b;
271	          end if;
272	
273	        when b =>
274	          if axi_lite_m2s.write.b.ready and axi_lite_s2m.write.b.valid then
275	            axi_lite_s2m.write.aw.ready <= '1';
276	            axi_lite_s2m.write.b.valid <= '0';
277	
278	            write_state <= aw;
279	          end if;
280	      end case;
281	
282	      if reset then
283	        write_state <= aw;
284	
285	        axi_lite_s2m.write.aw.ready <= '0';
286	        axi_lite_s2m.write.w.ready <= '0';
287	        axi_lite_s2m.write.b.valid <= '0';
288	      end if;
289	    end process;
290	
291	  end block;
292	
293	end architecture;
294

