231	    read => axi_lite_read_s2m_init,
232	    write => axi_lite_write_s2m_init
233	  );
234	
235	end;
236	
237	package body axi_lite_pkg is
238	
239	  ------------------------------------------------------------------------------
240	  function axi_lite_m2s_a_sz(addr_width : axi_lite_address_width_t) return positive is
241	  begin
242	    -- Excluded member: valid.
243	    return addr_width;
244	  end function;
245	  ------------------------------------------------------------------------------
246	
247	  ------------------------------------------------------------------------------
248	  function sanity_check_axi_lite_data_width(data_width : integer) return boolean is
249	    constant message : string := ". Got data_width=" & integer'image(data_width) & ".";
250	  begin
251	    if data_width /= 32 and data_width /= 64 then
252	      report "AXI-Lite data width must be either 32 or 64" & message;
253	      return false;
254	    end if;
255	
256	    return true;
257	  end function;
258	
259	  function to_axi_lite_strb(
260	    data_width : axi_lite_data_width_t
261	  ) return std_ulogic_vector is
262	    variable result : std_ulogic_vector(axi_lite_w_strb_sz - 1 downto 0) := (others => '0');
263	  begin
264	    assert sanity_check_axi_lite_data_width(data_width)
265	      report "Invalid data width, see printout above."
266	      severity failure;
267	
268	    result(data_width / 8 - 1 downto 0) := (others => '1');
269	
270	    return result;
271	  end function;
272	
273	  function axi_w_strb_width(data_width : axi_lite_data_width_t) return positive is
274	  begin
275	    assert sanity_check_axi_lite_data_width(data_width)
276	      report "Invalid data width, see printout above."
277	      severity failure;
278	
279	    return data_width / 8;
280	  end function;
281	
282	  function axi_lite_m2s_w_sz(data_width : axi_lite_data_width_t) return positive is
283	  begin
284	    assert sanity_check_axi_lite_data_width(data_width)
285	      report "Invalid data width, see printout above."
286	      severity failure;
287	
288	    -- Excluded member: valid
289	    return data_width + axi_w_strb_width(data_width);
290	  end function;
291	
292	  function to_slv(
293	    data : axi_lite_m2s_w_t; data_width : axi_lite_data_width_t
294	  ) return std_ulogic_vector is
295	    variable result : std_ulogic_vector(axi_lite_m2s_w_sz(data_width) - 1 downto 0);
296	    variable lo, hi : natural := 0;
297	  begin
298	    lo := 0;
299	    hi := lo + data_width - 1;
300	    result(hi downto lo) := data.data(data_width - 1 downto 0);
301	
302	    lo := hi + 1;
303	    hi := lo + axi_w_strb_width(data_width) - 1;
304	    result(hi downto lo) := data.strb(axi_w_strb_width(data_width) - 1 downto 0);
305	
306	    assert hi = result'high;
307	
308	    return result;
309	  end function;
310	
311	  function to_axi_lite_m2s_w(
312	    data : std_ulogic_vector; data_width : axi_lite_data_width_t
313	  ) return axi_lite_m2s_w_t is
314	    variable result : axi_lite_m2s_w_t := axi_lite_m2s_w_init;
315	    variable lo, hi : natural := 0;
316	  begin
317	    lo := 0;
318	    hi := lo + data_width - 1;
319	    result.data(data_width - 1 downto 0) := data(hi downto lo);
320	
321	    lo := hi + 1;
322	    hi := lo + axi_w_strb_width(data_width) - 1;
323	    result.strb(axi_w_strb_width(data_width) - 1 downto 0) := data(hi downto lo);
324	
325	    assert hi = data'high;
326	
327	    return result;
328	  end function;
329	  ------------------------------------------------------------------------------
330	
331	  ------------------------------------------------------------------------------
332	  function axi_lite_s2m_r_sz(data_width : axi_lite_data_width_t)  return positive is
333	  begin
334	    assert sanity_check_axi_lite_data_width(data_width)
335	      report "Invalid data width, see printout above."
336	      severity failure;
337	
338	    -- Excluded member: valid
339	    return data_width + axi_resp_sz;
340	  end function;
341	
342	  function to_slv(
343	    data : axi_lite_s2m_r_t; data_width : axi_lite_data_width_t
344	  ) return std_ulogic_vector is
345	    variable result : std_ulogic_vector(axi_lite_s2m_r_sz(data_width) - 1 downto 0);
346	    variable lo, hi : natural := 0;
347	  begin
348	    lo := 0;
349	    hi := lo + data_width - 1;
350	    result(hi downto lo) := data.data(data_width - 1 downto 0);
351	
352	    lo := hi + 1;
353	    hi := lo + axi_resp_sz - 1;
354	    result(hi downto lo) := data.resp;
355	
356	    assert hi = result'high;
357	
358	    return result;
359	  end function;
360	
361	  function to_axi_lite_s2m_r(
362	    data : std_ulogic_vector; data_width : axi_lite_data_width_t
363	  ) return axi_lite_s2m_r_t is
364	    variable result : axi_lite_s2m_r_t := axi_lite_s2m_r_init;
365	    variable lo, hi : natural := 0;
366	  begin
367	    lo := 0;
368	    hi := lo + data_width - 1;
369	    result.data(data_width - 1 downto 0) := data(hi downto lo);
370	
371	    lo := hi + 1;
372	    hi := lo + axi_resp_sz - 1;
373	    result.resp := data(hi downto lo);
374	
375	    assert hi = data'high;
376	
377	    return result;
378	  end function;
