1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	
10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	
14	library vunit_lib;
15	use vunit_lib.check_pkg.all;
16	use vunit_lib.com_pkg.net;
17	use vunit_lib.run_pkg.all;
18	
19	library osvvm;
20	use osvvm.RandomPkg.RandomPType;
21	
22	library bfm;
23	use bfm.axi_lite_bfm_pkg.all;
24	
25	library common;
26	use common.types_pkg.all;
27	
28	library axi_lite;
29	use axi_lite.axi_lite_pkg.all;
30	
31	use work.register_file_pkg.all;
32	
33	
34	entity tb_axi_lite_register_file is
35	  generic (
36	    runner_cfg : string
37	  );
38	end entity;
39	
40	architecture tb of tb_axi_lite_register_file is
41	
42	  -- Generic constants.
43	  shared variable rnd : RandomPType;
44	
45	  impure function initialize_and_get_regs return register_definition_vec_t is
46	    impure function initialize_and_get_num_registers return positive is
47	    begin
48	      -- This is the first function that is called, so we initialize the random number
49	      -- generator here.
50	      rnd.InitSeed(get_string_seed(runner_cfg));
51	
52	      -- We do some 'num_bits_needed' calculations in the DUT, so it is important that we test
53	      -- just below and above a power-of-two boundary.
54	      return rnd.Uniform(6, 34);
55	    end function;
56	    constant num_registers : positive := initialize_and_get_num_registers;
57	
58	    variable result : register_definition_vec_t(0 to num_registers - 1);
59	
60	    procedure set(index: natural; mode : register_mode_t) is
61	    begin
62	      result(index) := (index=>index, mode=>mode, utilized_width=>32);
63	    end procedure;
64	  begin
65	    for index in 0 to num_registers - 1 loop
66	      -- A few indexes are hardcoded in some tests below.
67	      if index < 2 then
68	        set(index=>index, mode=>r);
69	      elsif index < 4 then
70	        set(index=>index, mode=>w);
71	      elsif index < 6 then
72	        set(index=>index, mode=>r_w);
73	      else
74	        set(
75	          index=>index,
76	          mode=>register_mode_t'val(rnd.RandInt(register_mode_t'pos(register_mode_t'high)))
77	        );
78	      end if;
79	    end loop;
80	
81	    return result;
82	  end function;
83	  constant regs : register_definition_vec_t := initialize_and_get_regs;
84	
85	  impure function get_default_values return register_vec_t is
86	    variable result : register_vec_t(regs'range) := (others => (others => '0'));
87	  begin
88	    for index in regs'range loop
89	      result(index) := rnd.RandSlv(result(0)'length);
90	    end loop;
91	
92	    return result;
93	  end function;
94	  constant default_values : register_vec_t := get_default_values;
95	
96	  -- DUT connections.
97	  constant clk_period : time := 10 ns;
98	  signal clk, reset : std_ulogic := '0';
99	
100	  signal axi_lite_m2s : axi_lite_m2s_t := axi_lite_m2s_init;
101	  signal axi_lite_s2m : axi_lite_s2m_t := axi_lite_s2m_init;
102	
103	  signal regs_down, regs_up : register_vec_t(regs'range) := default_values;
104	  signal reg_was_read, reg_was_written : std_ulogic_vector(regs'range);
105	
106	  -- Testbench stuff.
107	  constant reg_was_accessed_zero : std_ulogic_vector(reg_was_written'range) := (others => '0');
108	
109	  signal regs_down_non_default_count : natural := 0;
110	
111	begin
112	
113	  test_runner_watchdog(runner, 100 us);
114	  clk <= not clk after clk_period / 2;
115	
116	
117	  ------------------------------------------------------------------------------
118	  main : process
119	    variable fabric_values, bus_values : register_vec_t(0 to regs'length - 1);
120	
121	    procedure reg_stimuli(reg : register_definition_t) is
122	    begin
123	      if is_write_mode(reg.mode) then
124	        write_bfm(net=>net, index=>reg.index, data=>bus_values(reg.index));
125	      end if;
126	
127	      if is_application_gives_value_mode(reg.mode) then
128	        regs_up(reg.index) <= fabric_values(reg.index);
129	      end if;
130	    end procedure;
131	
132	    procedure reg_data_check(reg : register_definition_t) is
133	      variable reg_was_accessed_expected : std_ulogic_vector(reg_was_written'range) := (
134	        others => '0'
135	      );
136	    begin
137	      reg_was_accessed_expected(reg.index) := '1';
138	
139	      if is_write_mode(reg.mode) then
140	        wait_for_write_to_go_through : while true loop
141	          if is_write_pulse_mode(reg.mode) then
142	            -- The value that fabric gets should be default all cycles except the one where the
143	            -- write happens
144	            check_equal(regs_down(reg.index), default_values(reg.index));
145	          end if;
146	
147	          wait until rising_edge(clk);
148	          if reg_was_written /= reg_was_accessed_zero then
149	            check_equal(reg_was_written, reg_was_accessed_expected);
150	            exit wait_for_write_to_go_through;
151	          end if;
152	        end loop;
153	
154	        check_equal(regs_down(reg.index), bus_values(reg.index), "index = " & to_string(reg.index));
155	      end if;
156	
157	      if is_write_pulse_mode(reg.mode) then
158	        wait until rising_edge(clk);
159	        -- The value that fabric gets should be default all cycles except the one where the
160	        -- write happens
161	        check_equal(regs_down(reg.index), default_values(reg.index));
162	      end if;
163	
164	      if is_read_mode(reg.mode) then
165	        if is_application_gives_value_mode(reg.mode) then
166	          check_bfm(net=>net, index=>reg.index, data=>fabric_values(reg.index));
167	        else
168	          check_bfm(net=>net, index=>reg.index, data=>bus_values(reg.index));
169	        end if;
170	
171	        wait until reg_was_read /= reg_was_accessed_zero and rising_edge(clk);
172	        check_equal(reg_was_read, reg_was_accessed_expected);
173	      end if;
174	    end procedure;
175	
176	  begin
177	    test_runner_setup(runner, runner_cfg);
178	
179	    for list_index in regs'range loop
180	      fabric_values(list_index) := rnd.RandSLV(fabric_values(0)'length);
181	      bus_values(list_index) := rnd.RandSLV(bus_values(0)'length);
182	    end loop;
183	    regs_up <= fabric_values;
184	
185	    if run("test_default_register_values") then
186	      wait for 10 * clk_period;
187	
188	      check_equal(regs_down_non_default_count, 0);
189	
190	    elsif run("test_random_write_then_read") then
191	      for list_index in regs'range loop
